-- ── 1. DROP & RECREATE src_sales ───────────────────────────

DROP TABLE IF EXISTS public.src_sales CASCADE;

CREATE TABLE public.src_sales (
    order_id        SERIAL PRIMARY KEY,
    order_date      DATE            NOT NULL,
    store_code      TEXT            NOT NULL,
    customer_id     TEXT            NOT NULL,
    product_id      TEXT            NOT NULL,
    quantity        INT             NOT NULL,
    unit_price      NUMERIC(12, 2)  NOT NULL,
    total_amount    NUMERIC(12, 2)  NOT NULL,
    partition_time  DATE            NOT NULL
);

-- ── Batch 1: January 2026 (18 rows, revenue = 2,670,000) ───

-- ── Batch 2: February 2026 (16 rows, revenue = 2,180,000) ──

