-- 2. DROP & RECREATE src_store
-- ════════════════════════════════════════════════════════════

DROP TABLE IF EXISTS public.src_store CASCADE;

CREATE TABLE public.src_store (
    store_code        VARCHAR(20),
    latitude          VARCHAR(20),
    longitude         VARCHAR(20),
    store_description TEXT,
    country           VARCHAR(10),
    area              TEXT,
    city              TEXT,
    district          TEXT,
    partition_time    TIMESTAMP
);

