-- 3. DROP & RECREATE src_customer
-- ════════════════════════════════════════════════════════════

DROP TABLE IF EXISTS public.src_customer CASCADE;

CREATE TABLE public.src_customer (
    customer_id       TEXT  NOT NULL,
    full_name         TEXT  NOT NULL,
    email             TEXT  NOT NULL,
    phone             TEXT  NOT NULL,
    city              TEXT  NOT NULL,
    province          TEXT  NOT NULL,
    registration_date DATE  NOT NULL,
    tier              TEXT  NOT NULL,
    partition_time    DATE  NOT NULL
);

