-- 4. VERIFICATION QUERIES
-- ════════════════════════════════════════════════════════════

-- src_sales per month
SELECT partition_time, COUNT(*) AS rows, SUM(total_amount) AS revenue
FROM public.src_sales GROUP BY 1 ORDER BY 1;
-- 2026-01-01 | 18 | 2,670,000
-- 2026-02-01 | 16 | 2,180,000
-- 2026-03-01 | 18 | 2,690,000
-- 2026-04-01 | 20 | 2,945,000
-- 2026-05-01 | 19 | 2,710,000
-- 2026-06-01 | 24 | 3,770,000
-- 2026-07-01 | 26 | 4,300,000
-- 2026-08-01 | 24 | 4,050,000
-- 2026-09-01 | 27 | 4,485,000

-- src_store per batch (should be 15 rows each)
SELECT partition_time::date, COUNT(*) AS stores
FROM public.src_store GROUP BY 1 ORDER BY 1;

-- src_customer per batch
SELECT partition_time, COUNT(*) AS customers
FROM public.src_customer GROUP BY 1 ORDER BY 1;
